import{_ as a,o,c as r,ae as n}from"./chunks/framework.C8MNLDzb.js";const u=JSON.parse('{"title":"《庄子》典故","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/zi/庄子.md","filePath":"docs/sucai/zi/庄子.md"}'),s={name:"docs/sucai/zi/庄子.md"};function e(i,t,g,h,l,d){return o(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="《庄子》典故" tabindex="-1">《庄子》典故 <a class="header-anchor" href="#《庄子》典故" aria-label="Permalink to &quot;《庄子》典故&quot;">​</a></h1><h2 id="庄周梦蝶" tabindex="-1">庄周梦蝶 <a class="header-anchor" href="#庄周梦蝶" aria-label="Permalink to &quot;庄周梦蝶&quot;">​</a></h2><p><strong>典故：</strong> 庄子梦见自己变成一只蝴蝶，翩翩飞舞，十分自在。醒来后却发现自己还是庄子。于是他疑惑：究竟是庄子梦见变成了蝴蝶，还是蝴蝶梦见变成了庄子？ <strong>出处：</strong> 《庄子·齐物论》 <strong>释义：</strong> 比喻人生如梦，世事无常。后也比喻艺术家陶醉于自己的创作中。</p><h2 id="望洋兴叹" tabindex="-1">望洋兴叹 <a class="header-anchor" href="#望洋兴叹" aria-label="Permalink to &quot;望洋兴叹&quot;">​</a></h2><p><strong>典故：</strong> 秋天涨水时，河伯以为自己是天下最壮大的，等他见到北海，才望洋向若而叹：&quot;野语有之曰：&#39;闻道百，以为莫己若&#39;者，我之谓也。&quot; <strong>出处：</strong> 《庄子·秋水》 <strong>释义：</strong> 仰望海洋，发出感叹。比喻做事时因力量不够或缺乏条件而感到无可奈何。</p><h2 id="庖丁解牛" tabindex="-1">庖丁解牛 <a class="header-anchor" href="#庖丁解牛" aria-label="Permalink to &quot;庖丁解牛&quot;">​</a></h2><p><strong>典故：</strong> 有一个名叫丁的厨师替梁惠王宰牛，手所接触的地方，肩所靠着的地方，脚所踩着的地方，膝所顶着的地方，都发出破裂的声音，而刀始终完好无损。 <strong>出处：</strong> 《庄子·养生主》 <strong>释义：</strong> 比喻技术纯熟，做事得心应手。</p><h2 id="涸辙之鱼" tabindex="-1">涸辙之鱼 <a class="header-anchor" href="#涸辙之鱼" aria-label="Permalink to &quot;涸辙之鱼&quot;">​</a></h2><p><strong>典故：</strong> 庄子家里断了粮，于是去找监河侯借粮。监河侯说等收了赋税再借给他。庄子气愤地说：昨天我看到干涸的车辙里有一条鱼，它请求给他斗升之水活命，我说去引西江的水来救它。鱼说：&quot;那就等死后在鱼铺里见吧。&quot; <strong>出处：</strong> 《庄子·外物》 <strong>释义：</strong> 比喻在困境中急需救援。</p><h2 id="邯郸学步" tabindex="-1">邯郸学步 <a class="header-anchor" href="#邯郸学步" aria-label="Permalink to &quot;邯郸学步&quot;">​</a></h2><p><strong>典故：</strong> 燕国有个人到赵国首都邯郸去，看到赵国人走路姿势很美，就跟着学。结果不但没学会赵国的走法，反而把自己原来的走法也忘了，只能爬着回去。 <strong>出处：</strong> 《庄子·秋水》 <strong>释义：</strong> 比喻模仿别人不成，反而丧失了原有的技能。</p><h2 id="孤雏腐鼠" tabindex="-1">孤雏腐鼠 <a class="header-anchor" href="#孤雏腐鼠" aria-label="Permalink to &quot;孤雏腐鼠&quot;">​</a></h2><p><strong>典故：</strong> 庄子去看望一个朋友，经过雁来小镇时，看到一只掉落的鸟雏，庄子说：&quot;这不过是一只孤雏腐鼠罢了！&quot; <strong>出处：</strong> 《庄子·秋水》 <strong>释义：</strong> 比喻微贱不足道的人或物。</p>',13)])])}const p=a(s,[["render",e]]);export{u as __pageData,p as default};
